To make the shape clonable, meaning that you can create multiple instances of the shape, modify the `sketch.js` file with the following code:

```javascript
let sidesSlider;
let sizeSlider;
let shapes = [];

function setup() {
  createCanvas(600, 400);
  sidesSlider = createSlider(3, 20, 3);
  sidesSlider.position(20, 20);

  sizeSlider = createSlider(50, min(width, height) / 2, min(width, height) / 4);
  sizeSlider.position(20, 50);

  textAlign(CENTER, CENTER);
}

function draw() {
  background(240);

  // Draw all shapes
  for (const shape of shapes) {
    const sides = shape.sides;
    const size = shape.size;
    translate(shape.x, shape.y);
    strokeWeight(4);
    stroke(50);
    fill(200);
    drawShape(sides, size);

    // Reset transformation
    translate(-shape.x, -shape.y);
  }
}

function drawShape(sides, radius) {
  let angle = TWO_PI / sides;
  beginShape();
  for (let i = 0; i < sides; i++) {
    let x = radius * cos(angle * i);
    let y = radius * sin(angle * i);
    vertex(x, y);
  }
  endShape(CLOSE);
}

function mouseReleased() {
  // Create a new shape at the cursor position with the current slider values
  const newShape = {
    x: mouseX,
    y: mouseY,
    sides: sidesSlider.value(),
    size: sizeSlider.value(),
  };
  shapes.push(newShape);
}
```

Now, instead of having only one shape, we store multiple shapes in an array called `shapes`. Each shape is an object with `x`, `y`, `sides`, and `size` properties. In the `draw()` function, we loop over the `shapes` array and draw each shape with its respective properties.

When you click anywhere on the canvas, a new shape is created at the cursor position with the current slider values for the number of sides and sizes.

To run the updated program, open the `index.html` file in your browser.

