    cursor('default');
  }
  // Check if user is clicking within the shape
  else if (dist(mouseX, mouseY, shapeCenter.x, shapeCenter.y) < minDist) {
    cursor('grab');
    if (mouseIsPressed) {
      dragging = true;
      cursor('grabbing');
    }
  } else {
    dragging = false;
    cursor('default');
  }
}

function mouseReleased() {
